INSERT INTO Alimentacion(objetivo, calorias, nombrePlato, descripcion, proteina, carbohidratos, grasas, foto) VALUES ('ganar fuerza', 633, 'Sándwich de aguacate y queso', 'Verduras, proteínas y grasas saludables: en este sándwich lo tienes todo! El aguacate es rico en grasas, pero no hay de qué preocuparse: nuestro cuerpo usa esos ácidos grasos insaturados en los procesos metabolicos.', 33.3, 27.3, 41.7,   )